mapper.select:
/* USE : PosLogCollectMgmtMapper.getSearchPosLogList */ SELECT C.HQ_OFFICE_CD , C.HQ_OFFICE_NM , A.STORE_CD , B.STORE_NM , TO_CHAR(TO_DATE(A.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , A.POS_NO , A.SEQ , A.COMMAND_ID , A.COMMAND_TYPE , A.LOG_TYPE , TO_CHAR(TO_DATE(A.DATE_FROM, 'yyyymmdd'), 'yyyy-mm-dd') AS START_DATE , TO_CHAR(TO_DATE(A.DATE_TO, 'yyyymmdd'), 'yyyy-mm-dd') AS END_DATE , A.SQL AS SQL , A.INCLUDE_DB_BACKUP AS DB_BACKUP , A.SMART_ORDER_YN AS SMART_ORDER , A.VCAT_PATH , A.REMARK , A.SEND_YN , A.SEND_DT , TO_CHAR(TO_DATE(A.REG_DT, 'YYYYMMDDHH24MISS'), 'yyyy-MM-dd HH24:MI:SS') AS REG_DT , (SELECT USER_NM FROM TB_WB_USER_INFO_DTL_V01 C WHERE C.USER_ID = A.REG_ID) AS REG_NM , A.STATUS , A.RESULT_CD , A.RESULT_MSG , A.DATA , A.ROW_COUNT , A.FILE_SIZE , TO_CHAR(TO_DATE(A.PROCESSED_AT, 'YYYYMMDDHH24MISS'), 'yyyy-MM-dd HH24:MI:SS') AS PROCESSED_AT , A.ERROR_MESSAGE FROM TB_MS_POS_LOG_COLLECTION_MANAGEMENT A , TB_MS_STORE B , TB_HQ_OFFICE C WHERE B.STORE_CD = A.STORE_CD AND C.HQ_OFFICE_CD = B.HQ_OFFICE_CD AND A.SALE_DATE BETWEEN #{startDate} AND #{endDate}
AND A.COMMAND_TYPE = #{commandType}
AND A.STORE_CD LIKE '%'||#{storeCd}||'%'
AND B.STORE_NM LIKE '%'||#{storeNm}||'%'
ORDER BY A.STORE_CD , A.SALE_DATE , A.POS_NO , A.SEQ

/* USE : PosLogCollectMgmtMapper.getMaxSeqNo */
SELECT  LPAD(NVL(MAX(SEQ), 0) + 1, 3, '0') AS SEQ
FROM    TB_MS_POS_LOG_COLLECTION_MANAGEMENT A
WHERE   A.STORE_CD      =   #{storeCd}
AND     A.SALE_DATE     =   #{saleDate}
AND     A.POS_NO        =   #{posNo}

mapper.insert:
/* PosLogCollectMgmtMapper.savePosLog */
INSERT INTO TB_MS_POS_LOG_COLLECTION_MANAGEMENT
(
        STORE_CD
,       SALE_DATE
,       POS_NO
,       SEQ
,       COMMAND_ID
,       COMMAND_TYPE
,       LOG_TYPE
,       DATE_FROM
,       DATE_TO
,       SQL
,       INCLUDE_DB_BACKUP
,       SMART_ORDER_YN
,       VCAT_PATH
,       REMARK
,       SEND_YN
,       SEND_DT
,       REG_DT
,       REG_ID
,       MOD_DT
,       MOD_ID
)
VALUES
(
        #{storeCd}
,       #{saleDate}
,       #{posNo}
,       #{seq}
,       #{storeCd} ||  #{saleDate} || #{posNo} || #{seq}
,       #{commandType}
,       #{logType}
,       #{dateFrom}
,       #{dateTo}
,       #{sql}
,       #{includeDbBackup}
,       #{smartOrderYn}
,       #{vcatPath}
,       #{remark}
,       'N'
,       ''
,       #{regDt}
,       #{regId}
,       #{modDt}
,       #{modId}
)
